import base64, os, sys, subprocess
content = base64.b64decode("").decode()
dest = "/opt/polymarket-agent/merge_apr30.py"
with open(dest, "w") as f:
    f.write(content)
# Clear pycache
for root, dirs, files in os.walk("/opt/polymarket-agent/__pycache__"):
    for f in files:
        if "merge_apr30" in f:
            os.remove(os.path.join(root, f))
            print(f"Cleared pycache: {f}")
sz = os.path.getsize(dest)
with open(dest) as f:
    data = f.read()
print(f"Written {sz:,} bytes")
print(f"sign_safe_hash: {'sign_safe_hash' in data}")
print(f"eth_keys: {'eth_keys' in data}")
print(f"execTransaction: {'execTransaction' in data}")
